+        "claude_code" => Some(crate::patterns::AgentType::ClaudeCode),
+        "gemini" => Some(crate::patterns::AgentType::Gemini),
+        "wezterm" => Some(crate::patterns::AgentType::Wezterm),
+        "unknown" => Some(crate::patterns::AgentType::Unknown),
+        _ => None,
+    }
